import { Link } from 'react-router-dom';

export default function Navbar() {
  return (
    <nav>
      <Link to="/">Home</Link>
      <Link to="/apply">Apply</Link>
      <Link to="/view">Applications</Link>
      <Link to="/update">Update</Link>
      <Link to="/status">Track Status</Link>
    </nav>
  );
}
